struct smr_region{
    struct list_head list;
    s8 name[64];
    phys_addr phys_start_addr;
    ulong size;
    struct list_head chunk_list_head;
}smr_region;

struct smr_chunk{
    struct list_head list;
    smr_region* smr_region;
    phys_addr phys_addr;
    void* kernel_addr;
    void* user_addr;
    u32 size;
    u32 flags;
    s32 ref_cnt;
}

struct smr_user_info{
    struct list_head list;
    s32 user_pid;
    struct list_head chunk_info_list_head;
}

struct smr_chunk_info{
    struct list_head list;
    smr_chunk* chunk;
    void* user_map_addr;
    u32 map_ref_cnt;
}每个结构体的作用，每个结构体里面参数的作用是什么？
